-- ================================================================
-- MIGRATION : Restructuration sous_categories_francais_cycle4
-- 69 lignes plates : id | classe | thematique | sous_categorie |
--                    objectifs_apprentissage (JSONB)
-- Ordre : thématique → sous-catégorie → 5e → 4e → 3e
-- ================================================================

BEGIN;

-- ── ÉTAPE 1 : Sauvegarder les anciennes tables ─────────────────
ALTER TABLE "competences_français_cycle4"
    RENAME TO _old_competences_francais_cycle4;

ALTER TABLE sous_categories_francais_cycle4
    RENAME TO _old_sous_categories_francais_cycle4;

-- ── ÉTAPE 2 : Créer la nouvelle table ──────────────────────────
CREATE TABLE sous_categories_francais_cycle4 (
    id                      SERIAL  PRIMARY KEY,
    classe                  TEXT    NOT NULL CHECK (classe IN ('5e', '4e', '3e')),
    thematique              TEXT    NOT NULL,
    sous_categorie          TEXT    NOT NULL,
    objectifs_apprentissage JSONB   NOT NULL DEFAULT '[]'::jsonb
);

-- ── ÉTAPE 3 : Insérer les 69 lignes ────────────────────────────

-- Réinitialiser la séquence de l'id
SELECT setval(pg_get_serial_sequence('sous_categories_francais_cycle4', 'id'), 69);

-- ── ÉTAPE 4 : Vérification (doit afficher 69 lignes) ───────────
SELECT
    id, classe, thematique, sous_categorie,
    jsonb_array_length(objectifs_apprentissage) AS nb_objectifs
FROM  sous_categories_francais_cycle4
ORDER BY id;

COMMIT;

-- ── NETTOYAGE (après vérification manuelle) ────────────────────
