INSERT INTO sous_categories_francais_cycle4
    (id, classe, thematique, sous_categorie, objectifs_apprentissage)
VALUES
    (1, '5e', 'Lecture', 'Comprendre, interpréter, apprécier', '["Rédiger un texte personnel pour rendre compte de sa réception et s''approprier sa lecture.", "Travailler la lecture silencieuse et développer les différentes stratégies de compréhension.", "Poursuivre son apprentissage de lecteur autonome, contrôler sa compréhension.", "Formuler un jugement fondé sur des émotions, sur des critères esthétiques, sur des idées et des valeurs.", "Justifier son point de vue de lecteur.", "Apprendre à recourir à quelques outils d''analyse pertinents pour lire les textes rencontrés."]'::jsonb),
    (2, '4e', 'Lecture', 'Comprendre, interpréter, apprécier', '["Écrire un texte d''une dizaine de lignes pour s''approprier sa lecture.", "Mettre en relation des informations pour comprendre l''implicite.", "Défendre et justifier son point de vue de lecteur dans un débat interprétatif en s''appuyant sur des éléments du texte.", "Mobiliser à bon escient quelques notions littéraires et outils d''analyse pour interpréter un texte.", "Justifier et réviser son appréciation."]'::jsonb),
    (3, '3e', 'Lecture', 'Comprendre, interpréter, apprécier', '["Écrire un texte d''une quinzaine de lignes pour s''approprier sa lecture.", "Identifier la ou les visées de textes et de supports variés.", "Justifier son interprétation en s''appuyant sur des éléments textuels variés.", "Approfondir sa lecture en mobilisant quelques notions littéraires et outils d''analyse pertinents.", "Percevoir des effets esthétiques et significatifs de la langue littéraire."]'::jsonb),
    (4, '5e', 'Lecture', 'Lire à voix haute, seul ou à plusieurs', '["Lire un texte d''une vingtaine de lignes avec aisance devant un auditoire.", "Lire un texte de manière expressive en utilisant les ressources de la voix, du rythme, du regard et éventuellement de la gestuelle.", "Réciter un court texte en vers ou en prose.", "Repérer des éléments à améliorer dans sa lecture oralisée ou celle des autres."]'::jsonb),
    (5, '4e', 'Lecture', 'Lire à voix haute, seul ou à plusieurs', '["Exprimer sa compréhension et son interprétation par sa lecture à voix haute.", "Réciter un texte, d''une quinzaine de lignes ou de vers, de manière expressive en s''appuyant sur la ponctuation.", "S''entrainer, seul ou avec ses pairs, pour améliorer sa lecture."]'::jsonb),
    (6, '3e', 'Lecture', 'Lire à voix haute, seul ou à plusieurs', '["Utiliser les ressources de la voix, de la respiration, du regard et de la gestuelle pour lire, pour jouer un texte.", "Réciter un texte, d''une vingtaine de lignes ou de vers, de manière expressive en s''appuyant sur la ponctuation.", "Comparer et apprécier différentes lectures ou mises en scène d''un texte."]'::jsonb),
    (7, '5e', 'Lecture', 'Appréhender une œuvre dans des contextes artistiques variés', '["Rendre compte de sa lecture personnelle d''une œuvre.", "Comprendre et interpréter le parcours d''un ou de plusieurs personnages afin d''appréhender les enjeux de l''œuvre et la situer dans son contexte.", "Comparer les langages différents d''une œuvre littéraire et d''une œuvre artistique.", "Tirer parti des informations sur le contexte de production d''une œuvre pour la comprendre et l''interpréter."]'::jsonb),
    (8, '4e', 'Lecture', 'Appréhender une œuvre dans des contextes artistiques variés', '["Comprendre, interpréter la structure globale d''une œuvre afin d''en appréhender les enjeux et de la situer dans son contexte.", "Comprendre, interpréter, apprécier une œuvre dans son contexte de publication.", "Comparer des œuvres littéraires et artistiques en utilisant un vocabulaire adapté.", "Connaitre quelques caractéristiques des genres littéraires abordés dans l''année."]'::jsonb),
    (9, '3e', 'Lecture', 'Appréhender une œuvre dans des contextes artistiques variés', '["Identifier des thèmes et des motifs littéraires au sein d''une œuvre et comparer leurs échos d''une œuvre à l''autre.", "Comprendre qu''une œuvre propose une représentation subjective.", "Formuler un jugement argumenté sur une œuvre en tenant compte de son contexte historique.", "Mobiliser sa connaissance du genre littéraire d''une œuvre et de son contexte de production pour affiner sa compréhension."]'::jsonb),
    (10, '5e', 'Lecture', 'Acquérir, structurer et mobiliser des connaissances littéraires et culturelles', '["S''approprier les mots importants de l''univers de l''œuvre étudiée.", "Mémoriser pour une œuvre intégrale étudiée un passage choisi d''une dizaine de lignes ou vers.", "Se constituer des repères dans l''histoire littéraire.", "Mettre en relation les textes nouveaux avec ceux de lus ou étudiés précédemment."]'::jsonb),
    (11, '4e', 'Lecture', 'Acquérir, structurer et mobiliser des connaissances littéraires et culturelles', '["Identifier quelques caractéristiques du style d''un auteur.", "Mémoriser pour une œuvre intégrale étudiée un passage choisi d''une quinzaine de lignes ou de vers.", "Relier les œuvres entre elles selon leurs contextes de création.", "Argumenter en prenant appui sur des exemples littéraires."]'::jsonb),
    (12, '3e', 'Lecture', 'Acquérir, structurer et mobiliser des connaissances littéraires et culturelles', '["Repérer quelques caractéristiques d''écriture (choix de langue, de formes et de procédés au service du sens) des textes et œuvres lus.", "Mémoriser dans une œuvre intégrale lue un passage d''une vingtaine de lignes ou de vers.", "Identifier quelques caractéristiques de périodes et de courants rencontrés à travers l''étude de textes et d''œuvres, les comparer et les mobiliser pour enrichir son interprétation.", "Situer les œuvres et les textes lus dans leur contexte géographique et culturel."]'::jsonb),
    (13, '5e', 'Culture littéraire et artistique', 'Entrées thématiques', '["Devenir héroïne/héros : destins romanesques (récit, fiction) - Surclassant l’humanité moyenne – des récits mythologiques ou bibliques jusqu’aux superhéroïnes et superhéros modernes –,\nles figures héroïques conjuguent bravoure, exploits extraordinaires et destins édifiants. Exemplaire, l’héroïne ou le héros met sa\npuissance d’incarnation au service d’une communauté qu’il soude, d’une société qu’il modèle ou d’une civilisation dont il\nfonde les valeurs. En prenant appui sur l’étude et l’appropriation d’une œuvre intégrale ou d’un groupement de textes, comme\nsur des lectures cursives, dans le cadre d’un projet d’apprentissage, l’élève s’interroge sur ces personnages hors-normes,\nmesure de l’Antiquité à nos jours la diversité de leurs représentations et appréhende les stéréotypes à l’œuvre dans les textes\nou leurs figurations canoniques. Plus largement au fil de l’année et de sa progression, il saisit les transformations en jeu, de\nl’épopée au roman moderne où le héros perd en superbe et gagne en banalité. L’élève est amené à s’interroger sur la\ntransmission des valeurs héroïques aujourd’hui.", "Voyager en poésie : « Du monde entier au cœur du monde » (poésie) - Par la poésie, l’invitation au voyage se démultiplie : l’exploration des horizons réels ou imaginaires jouxte celle des continents\nintérieurs, toutes deux sublimées par le dépaysement langagier. Un chemin est ainsi frayé « [d]u monde entier au cœur du\nmonde », selon la formule de Blaise Cendrars. En prenant appui sur l’étude et l’appropriation de larges extraits d’œuvres\nintégrales ou d’un groupement de textes, comme sur des lectures cursives, dans le cadre d’un projet d’apprentissage, l’élève\ndécouvre que la force des mots, des sonorités, des rythmes et des images projette le voyage bien au-delà du pittoresque. En\nrenouvelant le regard du lecteur, l’expérience poétique, empruntant à différentes traditions et cultures poétiques, y compris\nfrancophones, qu’elles soient patrimoniales ou contemporaines, révèle des espaces et des sensations insoupçonnés et ouvre à\nla découverte de soi, d’autrui et du monde. Plus largement, au fil de l’année et de sa progression, l’élève fait jouer la langue et\nles contraintes formelles pour en éprouver toute la richesse, notamment à travers des activités d’écriture créative et de lecture\nexpressive.", "Expérimenter et jouer au théâtre : la société sens dessus dessous (théâtre) - Amour d''un laquais pour une reine, fronde des valets, société sens dessus dessous : le théâtre aime à secouer, le temps de la représentation, le joug de l''ordre établi, à contester une pensée dominante et des conformismes sociaux, pour mieux libérer une force vitale subversive, héritière des traditions carnavalesques. En prenant appui sur l''étude et l''appropriation d''une œuvre théâtrale intégrale ou d''un groupement de textes, comme sur des lectures cursives, dans le cadre d''un projet d''apprentissage, l''élève mesure la portée des relations entre dominants et dominés, lorsqu''elles sont incarnées sur scène – et renversées. Il approfondit sa connaissance des spécificités de l''écriture et de la représentation théâtrales, et plus particulièrement de la dynamique du comique. Plus largement, au fil de l''année et de sa progression, en développant ses compétences de lecture et d''interprétation, en s''exerçant à des pratiques théâtrales variées (de la mise en voix, à l''écriture et à la mise en scène), il appréhende le sens et les valeurs de la mécanique du rire : il comprend que la scène en folie n''est jamais non-sens, mais miroir grossissant tendu aux spectateurs.", "Imaginer, sentir, raisonner : des histoires pour plaire et instruire (récit, fiction) - En prise avec les plaisirs de l''enfance, de son imaginaire, de ses sensations, l''univers du conte ou de la fable allie les charmes de la narration à la réflexion morale. En prenant appui sur l''étude et l''appropriation de larges extraits d''œuvres intégrales ou d''un groupement de textes, comme sur des lectures cursives, dans le cadre d''un projet d''apprentissage, l''élève comprend que les personnages incarnent différentes facettes de l''être humain, interroge leur conduite et le fonctionnement social qu''ils dévoilent, pour finalement se questionner lui-même. Plus largement, au fil de l''année et de sa progression, il découvre des œuvres narratives de traditions et cultures diverses, y compris francophones, qu''elles soient patrimoniales ou contemporaines. Par des débats, des écritures ou réécritures d''apologues, il développe un regard réflexif sur sa propre réception des récits et morales. Il goute ainsi le pouvoir de la littérature, capable tout à la fois de le faire voyager dans des contrées inconnues et des époques lointaines et de nourrir sa réflexion sur l''être humain et la vie en société. Cette entrée peut être l''occasion d''aborder, à partir de supports littéraires et / ou artistiques, des notions du programme d''éducation à la vie affective et relationnelle, et à la sexualité (ÉVARS)."]'::jsonb),
    (14, '4e', 'Culture littéraire et artistique', 'Entrées thématiques', '["Sonder, explorer, anticiper : la fiction aux limites de notre monde (récit, fiction) - Où s''arrête le réel ? Où commencent l''imaginaire et le rêve ? Récits fantastiques ou d''anticipation, enquêtes policières ou paranormales brouillent les frontières de la fiction pour accompagner l''exploration intranquille du réel. Qu''ils interrogent la survie de l''humanité face aux mutations technologiques, naturelles ou sociales, qu''ils expriment des peurs profondes ou questionnent les limites de la raison, tous invitent le lecteur à user d''esprit critique. En prenant appui sur l''étude et l''appropriation d''une œuvre intégrale ou d''un groupement de textes, comme sur des lectures cursives, dans le cadre d''un projet d''apprentissage, l''élève perçoit que la curiosité devant l''étrange peut être source de répulsion tout autant que de fascination. Plus largement, au fil de l''année et de sa progression, à mesure qu''il s''imprègne de ces récits, l''élève affine sa réception de textes qui stimulent sa créativité et peuvent enrichir ses pratiques d''écriture. Ces récits – qu''il est peu à peu capable de situer dans leurs époque et contexte de création –, l''invitent à aiguiser son analyse et exercer son discernement pour mieux appréhender la complexité du monde.", "Contempler, célébrer, veiller : habiter la terre en poète (poésie) - De la poésie orphique à la poésie contemporaine, le poète contemple et célèbre le monde. À l''instar de René Char, « veilleur qui attend l''aube » dans les Feuillets d''Hypnos, de Victor Hugo dans Les Rayons et les ombres ou d''Emily Dickinson, le poète est un regard qui veille et s''émerveille. Observateur attentif des réalités et des émotions humaines, il en saisit à la fois la beauté et les tensions, tout en mettant en lumière les injustices, les inégalités et les contradictions de son temps. En prenant appui sur l''étude et l''appropriation de larges extraits d''œuvres intégrales ou d''un groupement de textes, comme sur des lectures cursives, dans le cadre d''un projet d''apprentissage, l''élève découvre la multiplicité des regards que le poète pose sur le monde, la vie, la nature et les êtres, en étant sensible à la fragilité de son environnement. Au fil de l''année et de son cheminement, il prend conscience qu''habiter le monde en poète est une manière d''observer, de célébrer et de questionner ce qui l''entoure.", "Obéir, désobéir, trahir ? Conflits de valeurs sur scène (théâtre) - Si le conflit n''est pas spécifique au théâtre et constitue souvent le moteur du romanesque, la scène l''expose exemplairement aux yeux du spectateur comme moteur de l''action et objet de réflexion. En prenant appui sur l''étude et l''appropriation d''une œuvre intégrale ou d''un groupement de textes, comme sur des lectures cursives, dans le cadre d''un projet d''apprentissage, l''élève réfléchit à la manière dont, au théâtre, des systèmes de valeurs s''incarnent, s''opposent et se dépassent. Il perçoit les conflits de loyauté, les dilemmes qui peuvent en résulter et prend conscience que la scène est un espace de délibération et de construction de soi qui invite le spectateur à repenser ses propres valeurs. En développant son intérêt pour l''analyse de mises en scène, la scénographie, et la pratique théâtrale, l''élève prend en compte la dimension scénique au-delà de la seule étude textuelle. Hors du genre théâtral, il peut, lors de lectures cursives, envisager en écho certaines rencontres qui font vivre des chocs de valeurs : rencontre entre sociétés amérindiennes et premiers colons, guerre de Sécession, par exemple. Plus largement, au fil de l''année et de sa progression, l''élève comprend que l''obéissance, la désobéissance ou la trahison engagent des rapports de forces au sein desquels le débat intérieur et la liberté humaine prennent un relief majeur sur le plan dramatique, politique et axiologique (relatif à des valeurs philosophiques ou morales).", "Critiquer, dénoncer, penser : les Lumières en héritage (discours, essai, récit, fiction) - Penser l''héritage des Lumières, c''est mesurer, au-delà du seul XVIIIe siècle, la force émancipatrice des idées qu''elles font émerger et l''actualité toujours vive des combats humanistes qu''elles inspirent, en faveur de l''égalité, de la justice comme de l''accès au savoir. En prenant appui sur l''étude et l''appropriation d''une œuvre intégrale ou d''un groupement de textes, ainsi que sur des lectures cursives, dans le cadre d''un projet d''apprentissage, l''élève prend conscience que l''héritage des Lumières est toujours vivant et constitue une dynamique de pensée, une manière d''interroger le monde avec exigence et sensibilité. Dialoguant avec les œuvres d''hier et d''aujourd''hui, il développe et enrichit la dimension réflexive et argumentative de ses écrits et de ses prises de parole et formule sa pensée avec plus de justesse, de nuance et de force. Examiner, critiquer, douter, oser dénoncer, forger une pensée affranchie de la tutelle des dogmes et des préjugés sont autant de ferments des Lumières que l''élève fait siens en développant l''ambition et le courage de penser par lui-même. Au fil de l''année et de sa progression, il comprend que, loin d''être acquis pour toujours, l''héritage des Lumières est fragile et qu''il mérite d''être porté et défendu. Cette entrée peut être l''occasion d''aborder, à partir de supports littéraires et / ou artistiques, des notions du programme d''éducation à la vie affective et relationnelle, et à la sexualité (ÉVARS)."]'::jsonb),
    (15, '3e', 'Culture littéraire et artistique', 'Entrées thématiques', '["Montrer, témoigner, réparer : le roman, le récit à l''épreuve du réel (récit, fiction) - À mesure qu''ils s''affranchissent de l''héritage épique, roman et récit s''engagent dans un rapport privilégié et complexe avec le réel. Montrer, témoigner, tenter de réparer sont autant de possibles littéraires offerts à l''auteur. Ce dernier, s''efforçant de porter la voix de tous en même temps que la sienne, ouvre le lecteur à l''altérité, en orchestrant, selon la formule d''Alain Mabanckou, « le concert de la multiplicité d''expériences ». Les récits, du plus fictif au plus autobiographique, mettent à l''épreuve du réel l''auteur comme le lecteur : ils mettent des mots sur ce qui est perdu, invisible ou indicible ; ils s''efforcent de comprendre, et parfois de réparer les blessures, des souffrances intimes aux catastrophes humanitaires, sociales et/ou environnementales. En prenant appui sur l''étude et l''appropriation d''une œuvre intégrale ou d''un groupement de textes, comme sur des lectures cursives, dans le cadre d''un projet d''apprentissage, l''élève appréhende les potentialités de l''écriture romanesque et/ou autobiographique qui, en se confrontant à l''obstacle du réel, donnent matière à sentir, à connaitre et à penser, et inscrivent des voix singulières dans le tissu collectif. Plus largement, au fil de l''année et de sa progression, il mesure que l''écriture peut être un acte de justice symbolique, une tentative de recomposition des identités brisées ou des récits interrompus.", "S''unir, se désunir, se réunir en mots : l''amour en poésie (poésie) - Lesbie, Marie, Délie, Aurélia, Nadja, Elsa, Hélène… autant de muses incarnées dont le visage et la voix conjuguent amour et poésie. Dans le sillage d''Orphée, dont le chant nait de l''amour et de la rencontre de la mort, la poésie amoureuse se caractérise par la tension entre la célébration de l''amour fou, la joie de vivre, l''extrême sensibilité des perceptions et la souffrance profonde, le silence de l''absence ou de la distance, la douleur de la perte. Le singulier pouvoir de la lyre et la symbiose particulière de la parole et de la musique étendent les capacités expressives du langage et des mots pour, le temps d''un poème, restaurer l''unité et consoler l''inconsolable. Au moment où l''adolescent débute son éducation sentimentale, il peut entendre dans la poésie amoureuse et lyrique des échos de son expérience sensible, pour mieux se lire lui-même. En prenant appui sur l''étude et l''appropriation d''une œuvre poétique intégrale (recueil ou section de recueil) ou d''un groupement de textes, comme sur des lectures cursives, dans le cadre d''un projet d''apprentissage, il mesure la délicatesse du poète dans son rapport à la langue, son « hésitation prolongée entre le son et le sens » selon Valéry ; il éprouve la délectation sonore à dire la poésie et le plaisir de lire des textes polysémiques où jamais l''interprétation ne se fige. Plus largement, au fil de l''année et de sa progression, il discerne comment la poésie permet de partager des expériences singulières, comment la lecture et l''écriture peuvent constituer une médecine de l''âme par la parole. Cette entrée peut être l''occasion d''aborder, à partir de supports littéraires et / ou artistiques, des notions du programme d''éducation à la vie affective et relationnelle, et à la sexualité (ÉVARS).", "Représenter, penser, questionner la société au théâtre : la scène et la Cité (théâtre) - Lors des concours tragiques, c''est en lien direct avec les événements de la Cité que les tragédies antiques puisent dans les mythes. Dès son origine, le théâtre sert ainsi à « relier des éléments du présent à des questions éternelles », selon la formule d''Olivier Py. Les dramaturges français, francophones, étrangers qui réinvestissent les matériaux mythiques l''ont bien compris. Ils invitent leurs contemporains à questionner les valeurs sociales, à s''interroger sur eux-mêmes et sur le monde. En prenant appui sur l''étude et l''appropriation d''une œuvre théâtrale intégrale ou d''un groupement de textes, associés à des photogrammes et des captations de spectacles, comme sur des lectures cursives, et dans le cadre d''un projet d''apprentissage, l''élève mesure combien la scène théâtrale, par sa puissance d''incarnation et son effet sur le public, expose les forces antagonistes fondamentales de la Cité et agit sur elles. Il fréquente autant que possible le spectacle vivant pour développer son regard de spectateur. Plus largement, au fil de l''année et de sa progression, en pratiquant la lecture, la mise en voix, le jeu, la mise en scène, l''élève développe sa créativité et sa réflexion sur la dramaturgie et la scénographie, en même temps qu''il éprouve physiquement et intellectuellement la dynamique du débat et de la confrontation, au cœur des conflits de valeurs qui animent les sociétés d''hier et d''aujourd''hui.", "Défendre les valeurs humanistes : écrivains et journalistes acteurs de leur temps (articles, essai, récit) - Dès le début du XIXe siècle, l''essor de la presse bouleverse le champ littéraire : les écrivains deviennent journalistes, les journalistes se font écrivains et les modes d''écriture s''influencent. Dans cet espace médiatique en pleine expansion, qu''investissent bon nombre d''écrivaines, se déploie une parole critique, prenant position sur les affaires du monde. Car si le journaliste s''attache au fait brut, pris sur le vif, sa langue et sa subjectivité ne peuvent manquer de modeler le réel, toujours construit par l''écriture. Fouiller les profondeurs sociales, révéler l''insoupçonné ou « porter la plume dans la plaie », telle est ainsi l''ambition d''Hugo, Cendrars ou Albert Londres. En prenant appui sur l''étude et l''appropriation d''une œuvre intégrale ou d''un groupement de textes, ainsi que sur des lectures cursives, dans le cadre d''un projet d''apprentissage, l''élève prend conscience du pouvoir d''action de l''écriture. En analysant des œuvres qui rassemblent des articles, ainsi que des œuvres de reportage ou de témoignage, et en s''initiant à des pratiques d''écriture journalistique (chronique, reportage, tribune, lettre ouverte, etc.), il développe son propre regard critique sur le monde contemporain et ses médias d''information. Plus largement, au fil de l''année et de sa progression, il mesure que les mots – dans un contexte médiatique maitrisé – peuvent être des armes capables de toucher les consciences et de transformer le réel. Cette entrée peut être l''occasion d''aborder, à partir de supports littéraires et / ou artistiques, des notions du programme d''éducation à la vie affective et relationnelle, et à la sexualité (ÉVARS)."]'::jsonb),
    (16, '5e', 'Écriture', 'Écrire pour réfléchir, apprendre et mémoriser', '["Utiliser différents supports pour écrire, apprendre et mémoriser.", "Repérer l''idée principale d''un message écrit ou oral.", "Produire des écrits de travail : listes, synthèses, brouillons d''oral, etc."]'::jsonb),
    (17, '4e', 'Écriture', 'Écrire pour réfléchir, apprendre et mémoriser', '["Choisir de façon autonome les supports adaptés aux objectifs d''écriture.", "Prendre en notes un message oral ou écrit : organisation du propos et enchainement des idées.", "Utiliser l''écrit de travail en autonomie.", "S''initier aux écrits réflexifs."]'::jsonb),
    (18, '3e', 'Écriture', 'Écrire pour réfléchir, apprendre et mémoriser', '["S''initier à la prise de notes d''un message oral ou écrit pour apprendre et mémoriser dans toutes les disciplines.", "Maitriser les écrits de travail.", "Produire des écrits réflexifs."]'::jsonb),
    (19, '5e', 'Écriture', 'Écrire des textes d''invention et de réflexion pour soi et pour autrui', '["Planifier un écrit en étant accompagné dans sa démarche.", "S''initier à une pratique artistique et créative de l''écriture, seul ou avec ses pairs.", "Écrire des textes narratifs et descriptifs.", "Écrire un texte à visée argumentative à partir de consignes simples et explicitées."]'::jsonb),
    (20, '4e', 'Écriture', 'Écrire des textes d''invention et de réflexion pour soi et pour autrui', '["Planifier un écrit et devenir autonome.", "Développer une pratique artistique et créative de l''écriture, seul ou avec ses pairs.", "Écrire des textes libres, favorisant l''expression de soi, des sentiments et des idées.", "Écrire des textes qui mêlent les différents types de texte mêlant narration, description, paroles rapportées directement ou indirectement, en s''initiant aux codes propres aux genres et types de textes abordés.", "Écrire des textes à visée argumentative présentant au moins un argument et un exemple l''illustrant."]'::jsonb),
    (21, '3e', 'Écriture', 'Écrire des textes d''invention et de réflexion pour soi et pour autrui', '["Développer une pratique artistique et créative de l''écriture, seul ou avec ses pairs.", "Écrire de façon autonome des textes s''inscrivant dans des genres variés.", "Écrire un texte argumentatif structuré, en utilisant des stratégies variées.", "S''initier à la rédaction de courts textes d''analyse littéraire qui prennent appui sur un ou plusieurs faits de langue et de style simples et explicites."]'::jsonb),
    (22, '5e', 'Écriture', 'Évaluer son écrit et savoir le faire évoluer', '["Savoir utiliser le brouillon comme un écrit pour retravailler son texte.", "Réviser un écrit en suivant les consignes des professeurs.", "Faire évoluer un écrit en fonction de nouvelles consignes."]'::jsonb),
    (23, '4e', 'Écriture', 'Évaluer son écrit et savoir le faire évoluer', '["Construire des objectifs de relecture seul ou avec ses pairs.", "Améliorer un écrit en exploitant un lexique ou des lectures.", "Explorer les versions intermédiaires d''un texte, utiliser les ressorts du brouillon. Utiliser des dictionnaires variés imprimés ou en ligne, apprendre à utiliser un vérificateur orthographique, une grammaire, pour accompagner, améliorer ou corriger la production d''un écrit."]'::jsonb),
    (24, '3e', 'Écriture', 'Évaluer son écrit et savoir le faire évoluer', '["Développer un regard critique afin de faire évoluer son écrit de façon autonome.", "Enrichir un écrit à partir de ses lectures, savoir mobiliser l''intertextualité.", "Évaluer son écrit selon au moins deux critères : le respect de la consigne et celui des normes orthographiques et syntaxiques."]'::jsonb),
    (25, '5e', 'Oral', 'Prendre la parole, communiquer et interagir', '["Pratiquer un oral adapté à la situation de communication.", "Prendre la parole seul et s''exprimer de façon fluide.", "Entrer dans un dialogue.", "Intervenir dans un débat en respectant les règles d''un échange argumentatif."]'::jsonb),
    (26, '4e', 'Oral', 'Prendre la parole, communiquer et interagir', '["Pratiquer un oral construit adapté à la situation de communication.", "Prendre la parole sans préparation.", "Prendre part de manière active et raisonnée à un débat."]'::jsonb),
    (27, '3e', 'Oral', 'Prendre la parole, communiquer et interagir', '["S''exprimer en continu à l''oral de façon maitrisée.", "Interagir avec autrui, en s''ajustant au contexte de communication.", "Prendre part à un débat, l''animer ou l''arbitrer."]'::jsonb),
    (28, '5e', 'Oral', 'Écouter, comprendre et interpréter', '["Écouter une production orale et en mémoriser les principaux éléments.", "Comprendre les visées d''une production orale spécifique."]'::jsonb),
    (29, '4e', 'Oral', 'Écouter, comprendre et interpréter', '["Écouter une production orale et en mémoriser les idées principales.", "Distinguer l''explicite et l''implicite.", "Comprendre dans une production orale l''organisation des informations et pouvoir la restituer."]'::jsonb),
    (30, '3e', 'Oral', 'Écouter, comprendre et interpréter', '["Écouter et comprendre une production orale en autonomie.", "Distinguer les arguments et les exemples dans un message oral.", "Identifier le thème et les thèses d''un message oral.", "Formuler l''implicite d''un message oral."]'::jsonb),
    (31, '5e', 'Oral', 'Dire, lire, jouer un texte', '["Lire et réciter avec fluidité.", "Utiliser les ressources de la voix et du corps pour faire vivre un texte.", "S''exercer à la pratique théâtrale."]'::jsonb),
    (32, '4e', 'Oral', 'Dire, lire, jouer un texte', '["Lire et réciter avec expressivité pour autrui.", "Prendre en compte un auditoire.", "Jouer une scène de théâtre."]'::jsonb),
    (33, '3e', 'Oral', 'Dire, lire, jouer un texte', '["Réciter et interpréter avec une intention expressive.", "Interpréter et mettre en scène un texte théâtral.", "Pratiquer des genres variés de l''oral."]'::jsonb),
    (34, '5e', 'Vocabulaire et orthographe lexicale', 'Enrichir son vocabulaire', '["Savoir déduire, vérifier ou rechercher le sens d''un mot.", "Mobiliser le vocabulaire nouveau pour améliorer ses productions écrites et orales.", "Organiser les savoirs lexicaux (collections, familles de mots, portfolios, etc.).", "Maitriser l''usage du dictionnaire de langue en version papier et numérique."]'::jsonb),
    (35, '4e', 'Vocabulaire et orthographe lexicale', 'Enrichir son vocabulaire', '["Enrichir son lexique de l''analyse littéraire, en particulier celui du théâtre et du roman.", "Questionner en s''appuyant sur le contexte les conditions d''emploi d''un lexique (époque, lieu, etc.).", "Justifier l''emploi de son lexique à l''oral.", "Construire un lexique interdisciplinaire.", "Maitriser la consultation d''un dictionnaire de langue ou une encyclopédie lorsque les stratégies déductives ne suffisent pas pour éclairer le sens."]'::jsonb),
    (36, '3e', 'Vocabulaire et orthographe lexicale', 'Enrichir son vocabulaire', '["Mettre en relation des informations lexicales pour comprendre et affiner sa compréhension de l''implicite.", "Compléter son lexique de l''analyse littéraire, en particulier celui de la poésie et de l''argumentation.", "Maitriser les outils d''analyse stylistique essentiels.", "Explorer la variété des dictionnaires : historique, étymologique, culturel."]'::jsonb),
    (37, '5e', 'Vocabulaire et orthographe lexicale', 'Identifier les types de relations entre les mots', '["Reconnaitre et savoir nommer les relations de sens entre les mots.", "Reconnaitre et savoir nommer les relations de forme (morphologie) entre les mots.", "S''appuyer sur la composition d''un mot (préfixe, radical, suffixe) pour en déduire le sens."]'::jsonb),
    (38, '4e', 'Vocabulaire et orthographe lexicale', 'Identifier les types de relations entre les mots', '["Consolider la connaissance des relations de sens entre les mots (glissements et variations de sens, locutions).", "Consolider la connaissance des relations de forme entre les mots (composition).", "Mettre les mots en réseau.", "Maitriser le classement par degré d''intensité et de généralité, et les utiliser à l''écrit et à l''oral."]'::jsonb),
    (39, '3e', 'Vocabulaire et orthographe lexicale', 'Identifier les types de relations entre les mots', '["Identifier et interpréter les effets de mise en réseau des mots dans le texte.", "Identifier et utiliser à bon escient les mots de liaison et connecteurs qui permettent l''articulation de la pensée.", "Comprendre que le lexique fonctionne comme un univers organisé par les types de relation entre les mots.", "Diversifier et nuancer son expression."]'::jsonb),
    (40, '5e', 'Vocabulaire et orthographe lexicale', 'Réemployer son lexique et jouer avec les mots', '["Utiliser les mots en exploitant les variations de sens.", "Distinguer les registres de langue et les utiliser en s''ajustant au contexte, à l''écrit comme à l''oral.", "Comprendre le fonctionnement du néologisme (de forme et de sens).", "Jouer avec les mots comme matériau sonore."]'::jsonb),
    (41, '4e', 'Vocabulaire et orthographe lexicale', 'Réemployer son lexique et jouer avec les mots', '["Analyser en contexte le sens des mots : polysémie et synonymie, antonymie et homonymie, dénotation et connotation.", "Comparer le vocabulaire et le sens des mots entre des textes de même genre ou de même période.", "Explorer la variation des mots en traduction et en adaptation.", "Expérimenter les jeux d''expansion, de reprise ou de déplacement des mots."]'::jsonb),
    (42, '3e', 'Vocabulaire et orthographe lexicale', 'Réemployer son lexique et jouer avec les mots', '["Distinguer la dénotation et la connotation et comprendre les types de connotations.", "Identifier et produire des écrits s''appuyant sur l''imitation.", "Identifier et produire des écrits en augmentation d''un texte.", "Comprendre et imiter les effets sémantiques de la disposition des mots sur la page."]'::jsonb),
    (43, '5e', 'Vocabulaire et orthographe lexicale', 'Comprendre la formation des mots', '["Consolider la connaissance de la formation des mots, repérer les analogies, les régularités entre eux.", "Connaitre le sens des préfixes et suffixes les plus fréquents.", "Appréhender la dimension historique des mots (étymologie) en maitrisant quelques éléments latins, grecs ou empruntés aux langues étrangères.", "Comprendre le principe de la dérivation des mots et son incidence sur l''orthographe."]'::jsonb),
    (44, '4e', 'Vocabulaire et orthographe lexicale', 'Comprendre la formation des mots', '["Approfondir la connaissance de la formation des mots, distinguer des régularités et des exceptions.", "Décrire et justifier l''emploi des préfixes et suffixes les plus fréquents.", "Appréhender la dimension historique des mots à travers quelques exemples d''évolutions de sens et de graphies."]'::jsonb),
    (45, '3e', 'Vocabulaire et orthographe lexicale', 'Comprendre la formation des mots', '["Observer avec précision l''écart entre le code oral et le code écrit.", "Comprendre et exploiter la formation lexicale.", "Apprécier en lecture et en écriture le degré de précision d''un énoncé par la formation des mots.", "Développer une stratégie de recherche autonome du sens d''un mot par sa formation."]'::jsonb),
    (46, '5e', 'Vocabulaire et orthographe lexicale', 'Écrire avec justesse (orthographe)', '["Mémoriser l''orthographe du vocabulaire rencontré.", "Utiliser sa connaissance de l''étymologie pour orthographier des mots ayant le même radical.", "Construire des réflexes d''écriture en s''appuyant sur les régularités orthographiques."]'::jsonb),
    (47, '4e', 'Vocabulaire et orthographe lexicale', 'Écrire avec justesse (orthographe)', '["S''appuyer sur la morphologie des mots pour en déduire leur orthographe.", "Développer un raisonnement pour résoudre les difficultés orthographiques liées aux radicaux verbaux (indicatif et impératif).", "Construire des réflexes orthographiques : les conjonctions et leurs homophones."]'::jsonb),
    (48, '3e', 'Vocabulaire et orthographe lexicale', 'Écrire avec justesse (orthographe)', '["Exploiter les connaissances morphologiques des mots.", "Développer un raisonnement pour résoudre les difficultés orthographiques des radicaux verbaux (conditionnel, subjonctif).", "Consolider les réflexes orthographiques pour orthographier les homophones lexicaux."]'::jsonb),
    (49, '5e', 'Grammaire et orthographe grammaticale', 'Comprendre ce qu''est une phrase pour mieux lire et mieux écrire', '["Identifier et réinvestir le rôle des différents signes de ponctuation en lien avec les constituants de la phrase.", "Identifier trois types de phrases et analyser leurs effets dans un texte.", "Reconnaitre trois formes de phrases et leurs caractéristiques (exclamative et négative).", "Comprendre et expliciter la différence entre phrase simple, phrase complexe, phrase non verbale.", "Comprendre, identifier et employer les relations entre les propositions.", "Comprendre les effets de sens produits par les relations de juxtaposition et coordination.", "Organiser la progression d''un texte et assurer sa cohérence par l''enchainement des phrases."]'::jsonb),
    (50, '4e', 'Grammaire et orthographe grammaticale', 'Comprendre ce qu''est une phrase pour mieux lire et mieux écrire', '["Employer à bon escient le point-virgule.", "Comprendre la relation de subordination en analysant les liens entre proposition principale et proposition subordonnée.", "Analyser l''enchainement et l''imbrication des propositions subordonnées.", "Comprendre les fonctions grammaticales des propositions subordonnées relatives et conjonctives.", "Identifier la proposition subordonnée interrogative indirecte dans le cadre d''une interrogation totale ou partielle."]'::jsonb),
    (51, '3e', 'Grammaire et orthographe grammaticale', 'Comprendre ce qu''est une phrase pour mieux lire et mieux écrire', '["Employer à bon escient le point-virgule et la virgule dans des phrases aux structures plus complexes.", "Identifier la phrase de forme emphatique et ses différents modes de construction.", "Comprendre les fonctions grammaticales des propositions subordonnées conjonctives et circonstancielles en évitant l''exhaustivité.", "Comprendre le fonctionnement du pronom relatif.", "Employer des connecteurs logiques variés pour assurer la progression logique d''un texte."]'::jsonb),
    (52, '5e', 'Grammaire et orthographe grammaticale', 'Connaitre les différents constituants d''une phrase', '["Analyser les constituants du groupe sujet, du groupe verbal et du groupe circonstanciel.", "Identifier le sujet, les compléments d''objet direct et indirect, l''attribut du sujet, les compléments circonstanciels de lieu, de cause, de temps et de manière, en utilisant des manipulations syntaxiques et en verbalisant son raisonnement pour s''assurer de sa compréhension.", "Comprendre la structure du groupe nominal minimal et du groupe nominal étendu ; les identifier dans une phrase ou un court passage.", "Identifier les prépositions, les adverbes et les mots subordonnants.", "Distinguer les déterminants et les pronoms.", "Identifier les pronoms personnels, démonstratifs et indéfinis, sans chercher l''exhaustivité.", "Identifier les mots coordonnants et comprendre leurs rôles syntaxique et sémantique dans la phrase."]'::jsonb),
    (53, '4e', 'Grammaire et orthographe grammaticale', 'Connaitre les différents constituants d''une phrase', '["Identifier et nommer les conjonctions de subordination et pronoms relatifs, sans chercher l''exhaustivité.", "Identifier les fonctions des propositions subordonnées conjonctives et relatives.", "Identifier les fonctions de complément circonstanciel d''opposition, de condition et la fonction apposition.", "Approfondir l''analyse de la structure du groupe nominal étendu et de ses différentes fonctions grammaticales.", "Organiser la progression d''un texte comportant des subordonnées et assurer sa cohérence et sa cohésion."]'::jsonb),
    (54, '3e', 'Grammaire et orthographe grammaticale', 'Connaitre les différents constituants d''une phrase', '["Consolider l''identification de différentes fonctions grammaticales dans des structures plus complexes (subordonnées complétives, circonstancielles et subordonnées relatives).", "Consolider l''identification du groupe verbal dans des structures plus complexes comprenant des subordonnées conjonctives ou des groupes prépositionnels.", "Consolider l''identification du groupe nominal étendu lorsqu''il comporte des structures plus complexes : subordonnées relatives, groupes prépositionnels et adjectivaux."]'::jsonb),
    (55, '5e', 'Grammaire et orthographe grammaticale', 'Observer et distinguer les registres de langue et ajuster ses choix au contexte', '["Découvrir et comprendre les différences entre grammaire de l''écrit et grammaire de l''oral (registre de langue, syntaxe, langue écrite ou parlée plus ou moins normée, contexte d''énonciation)."]'::jsonb),
    (56, '4e', 'Grammaire et orthographe grammaticale', 'Observer et distinguer les registres de langue et ajuster ses choix au contexte', '["Identifier les différents registres de langue.", "Employer le registre de langue courant, contrôlé, voire soutenu, dans un oral scolaire et en exclure volontairement le registre de langue familier."]'::jsonb),
    (57, '3e', 'Grammaire et orthographe grammaticale', 'Observer et distinguer les registres de langue et ajuster ses choix au contexte', '["Adapter son registre de langue dans le cadre d''un oral scolaire, en excluant volontairement le registre de langue familier.", "Comprendre que les écrivains peuvent employer tous les registres de langue selon les effets recherchés sur le lecteur."]'::jsonb),
    (58, '5e', 'Grammaire et orthographe grammaticale', 'Analyser et employer des paroles rapportées', '["Identifier des paroles rapportées aux discours direct et indirect.", "Insérer des paroles au discours direct dans un texte."]'::jsonb),
    (59, '4e', 'Grammaire et orthographe grammaticale', 'Analyser et employer des paroles rapportées', '["Insérer dans un texte des paroles rapportées au discours indirect en alternance avec le discours direct."]'::jsonb),
    (60, '3e', 'Grammaire et orthographe grammaticale', 'Analyser et employer des paroles rapportées', '["Identifier des paroles rapportées au discours indirect libre et en apprécier les effets littéraires.", "Comprendre l''alternance de différentes formes de paroles rapportées dans un récit."]'::jsonb),
    (61, '5e', 'Grammaire et orthographe grammaticale', 'Maitriser la composition des formes verbales pour identifier un temps et le conjuguer', '["Découvrir, comprendre et mémoriser les éléments qui constituent une forme verbale : radical verbal et terminaison (marques de temps et de personne).", "Comprendre la morphologie des temps simples (présent, futur simple, imparfait, passé simple de l''indicatif, conditionnel et présent de l''impératif) et des temps composés (passé composé et plus-que-parfait de l''indicatif).", "Conjuguer un verbe par imitation, au passé antérieur et au futur antérieur de l''indicatif.", "Consolider la conjugaison des verbes réguliers et des principaux verbes irréguliers en fonction de la variation de leur radical."]'::jsonb),
    (62, '4e', 'Grammaire et orthographe grammaticale', 'Maitriser la composition des formes verbales pour identifier un temps et le conjuguer', '["Découvrir, comprendre et mémoriser les éléments qui caractérisent les temps composés (plus-que-parfait, passé antérieur, futur antérieur et conditionnel passé de l''indicatif).", "Identifier la morphologie du plus-que-parfait, du futur antérieur et du conditionnel dans un texte, en explicitant sa démarche.", "Mémoriser les particularités orthographiques des participes passés en -é, -i, -u ainsi que les formes avec une consonne finale muette.", "Comprendre la construction de la voix passive.", "Maitriser la conjugaison des verbes réguliers et des principaux verbes irréguliers en fonction de la variation de leur radical, sans viser l''exhaustivité."]'::jsonb),
    (63, '3e', 'Grammaire et orthographe grammaticale', 'Maitriser la composition des formes verbales pour identifier un temps et le conjuguer', '["Identifier tous les temps connus dans un texte en raisonnant sur la morphologie des verbes.", "Employer et identifier le présent et le passé du subjonctif à l''écrit et à l''oral.", "Connaitre la morphologie du passé du subjonctif.", "Maitriser la conjugaison des verbes réguliers et des principaux verbes irréguliers en fonction de la variation de leur radical sans viser l''exhaustivité."]'::jsonb),
    (64, '5e', 'Grammaire et orthographe grammaticale', 'Maitriser l''emploi des temps et des modes', '["Approfondir sa maitrise des valeurs temporelles et aspectuelles des temps simples et composés.", "Approfondir sa maitrise des modes indicatif et impératif."]'::jsonb),
    (65, '4e', 'Grammaire et orthographe grammaticale', 'Maitriser l''emploi des temps et des modes', '["Étudier la valeur temporelle et les valeurs modales du conditionnel.", "Approfondir l''emploi des valeurs aspectuelles des temps étudiés précédemment : borné et non borné, accompli et non accompli.", "Identifier les valeurs du mode subjonctif."]'::jsonb),
    (66, '3e', 'Grammaire et orthographe grammaticale', 'Maitriser l''emploi des temps et des modes', '["Maitriser l''emploi des voix, des modes (emplois élargis du subjonctif après certaines conjonctions) et des valeurs aspectuelles et temporelles des temps.", "Consolider la maitrise du conditionnel et comprendre ses différents emplois : temps verbal de l''indicatif qui présente des valeurs temporelles et modales."]'::jsonb),
    (67, '5e', 'Grammaire et orthographe grammaticale', 'Savoir accorder les mots dans la phrase et expliquer ses choix', '["Maitriser les chaines d''accord du groupe nominal en développant son raisonnement.", "Maitriser les chaines d''accord de l''attribut du sujet en développant son raisonnement.", "Maitriser les cas complexes de l''accord sujet-verbe (sujet séparé du verbe par un complément, sujet comportant plusieurs noms).", "Justifier à l''oral ou à l''écrit l''accord du participe passé employé avec l''auxiliaire être et avec l''auxiliaire avoir (COD antéposé dont pronom personnel COD, à distinguer du COI). Identifier les verbes attributifs en repérant l''emploi occasionnellement attributif de certains verbes.", "Identifier et comprendre les caractéristiques spécifiques de l''attribut du sujet."]'::jsonb),
    (68, '4e', 'Grammaire et orthographe grammaticale', 'Savoir accorder les mots dans la phrase et expliquer ses choix', '["Comprendre et maitriser le fonctionnement des chaines d''accord dans un groupe nominal présentant un déterminant indéfini.", "Comprendre, mémoriser et maitriser l''accord du verbe avec le sujet dans des cas complexes (sujet comportant plusieurs personnes et pronom relatif sujet).", "Découvrir l''accord du participe passé des verbes pronominaux."]'::jsonb),
    (69, '3e', 'Grammaire et orthographe grammaticale', 'Savoir accorder les mots dans la phrase et expliquer ses choix', '["Maitriser l''accord au sein du groupe nominal (minimal et étendu : avec une proposition subordonnée relative comprise dans le groupe nominal).", "Maitriser l''accord de l''adjectif ou du groupe adjectival (fonctions épithète, attribut et apposition).", "Maitriser l''accord du participe passé (auxiliaire avoir avec un complément d''objet direct pronom relatif placé avant le verbe).", "Maitriser l''accord sujet-verbe dans des cas complexes (pronom collectif ou distributif comme sujet, groupe nominal incluant un complément du nom)."]'::jsonb);
